def solve(*args):
    if len(args) != 1 or not isinstance(args[0], str):
        raise ValueError("Input must be a single string.")

    input_string = args[0]
    char_count = {}

    for char in input_string:
        if char in char_count:
            char_count[char] += 1
        else:
            char_count[char] = 1

    return dict(sorted(char_count.items()))
